// Package excelize providing a set of functions that allow you to write to and
// read from XLAM / XLSM / XLSX / XLTM / XLTX files. Supports reading and
// writing spreadsheet documents generated by Microsoft Excel™ 2007 and later.
// Supports complex components by high compatibility, and provided streaming
// API for generating or reading data from a worksheet with huge amounts of
// data. This library needs Go version 1.25.0 or later.

package excelize

import (
	"bytes"
	"encoding/binary"
	"encoding/xml"
	"io"
	"math"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"sync"
)

// NewFile provides a function to create new file by default template.
// For example:
//
//	f := NewFile()
func NewFile(opts ...Options) *File {
	f := newFile()
	f.Pkg.Store(defaultXMLPathRels, []byte(xml.Header+templateRels))
	f.Pkg.Store(defaultXMLPathDocPropsApp, []byte(xml.Header+templateDocpropsApp))
	f.Pkg.Store(defaultXMLPathDocPropsCore, []byte(xml.Header+templateDocpropsCore))
	f.Pkg.Store(defaultXMLPathWorkbookRels, []byte(xml.Header+templateWorkbookRels))
	f.Pkg.Store(defaultXMLPathTheme, []byte(xml.Header+templateTheme))
	f.Pkg.Store(defaultXMLPathSheet, []byte(xml.Header+templateSheet))
	f.Pkg.Store(defaultXMLPathStyles, []byte(xml.Header+templateStyles))
	f.Pkg.Store(defaultXMLPathWorkbook, []byte(xml.Header+templateWorkbook))
	f.Pkg.Store(defaultXMLPathContentTypes, []byte(xml.Header+templateContentTypes))
	f.SheetCount = 1
	f.CalcChain, _ = f.calcChainReader()
	f.ContentTypes, _ = f.contentTypesReader()
	f.Styles, _ = f.stylesReader()
	f.WorkBook, _ = f.workbookReader()
	f.Relationships = sync.Map{}
	rels, _ := f.relsReader(defaultXMLPathWorkbookRels)
	f.Relationships.Store(defaultXMLPathWorkbookRels, rels)
	f.sheetMap["Sheet1"] = defaultXMLPathSheet
	ws, _ := f.workSheetReader("Sheet1")
	f.Sheet.Store(defaultXMLPathSheet, ws)
	f.Theme, _ = f.themeReader()
	f.options = f.getOptions(opts...)
	return f
}

// Save provides a function to override the spreadsheet with origin path.
func (f *File) Save(opts ...Options) error {
	if f.Path == "" {
		return ErrSave
	}
	for i := range opts {
		f.options = &opts[i]
	}
	return f.SaveAs(f.Path, *f.options)
}

// SaveAs provides a function to create or update to a spreadsheet at the
// provided path.
func (f *File) SaveAs(name string, opts ...Options) error {
	if countUTF16String(name) > MaxFilePathLength {
		return ErrMaxFilePathLength
	}
	f.Path = name
	if _, ok := supportedContentTypes[strings.ToLower(filepath.Ext(f.Path))]; !ok {
		return ErrWorkbookFileFormat
	}
	file, err := os.OpenFile(filepath.Clean(name), os.O_WRONLY|os.O_TRUNC|os.O_CREATE, os.ModePerm)
	if err != nil {
		return err
	}
	defer func() {
		_ = file.Close()
	}()
	return f.Write(file, opts...)
}

// Close closes and cleanup the open temporary file for the spreadsheet.
func (f *File) Close() error {
	var firstErr error
	if f.sharedStringTemp != nil {
		firstErr = f.sharedStringTemp.Close()
		f.sharedStringTemp = nil
	}
	for _, stream := range f.streams {
		_ = stream.rawData.Close()
	}
	f.streams = nil
	f.tempFiles.Range(func(k, v interface{}) bool {
		if err := os.Remove(v.(string)); err != nil && firstErr == nil {
			firstErr = err
		}
		return true
	})
	f.tempFiles.Clear()
	return firstErr
}

// Write provides a function to write to an io.Writer.
func (f *File) Write(w io.Writer, opts ...Options) error {
	_, err := f.WriteTo(w, opts...)
	return err
}

// WriteTo implements io.WriterTo to write the file. When no password
// encryption is required, the ZIP archive is streamed directly to w without
// buffering the entire compressed output in memory. When password encryption
// is required, a temporary file is used to reduce memory usage.
func (f *File) WriteTo(w io.Writer, opts ...Options) (int64, error) {
	for i := range opts {
		f.options = &opts[i]
	}
	if len(f.Path) != 0 {
		contentType, ok := supportedContentTypes[strings.ToLower(filepath.Ext(f.Path))]
		if !ok {
			return 0, ErrWorkbookFileFormat
		}
		if err := f.setContentTypePartProjectExtensions(contentType); err != nil {
			return 0, err
		}
	}
	// Password encryption requires post-processing the entire output.
	// Use a temporary file to reduce peak memory usage.
	if f.options != nil && f.options.Password != "" {
		return f.writeToWithEncryption(w)
	}
	// Stream the ZIP directly to w. This avoids holding the full compressed
	// archive in a bytes.Buffer, which can be 50-200 MB+ for large reports.
	cw := &countWriter{w: w}
	zw := f.ZipWriter(cw)
	f.configureZipCompression(zw)
	if err := f.writeToZip(zw); err != nil {
		_ = zw.Close()
		return cw.n, err
	}
	return cw.n, zw.Close()
}

// writeToWithEncryption writes an encrypted file using a temporary file to
// reduce memory usage. This avoids buffering the entire ZIP in memory before
// encryption.
func (f *File) writeToWithEncryption(w io.Writer) (int64, error) {
	var tmpDir string
	if f.options != nil {
		tmpDir = f.options.TmpDir
	}
	// Create temporary file for the unencrypted ZIP
	tmpFile, err := os.CreateTemp(tmpDir, "excelize-encrypt-*.zip")
	if err != nil {
		return 0, err
	}
	tmpPath := tmpFile.Name()
	defer func() {
		_ = tmpFile.Close()
		_ = os.Remove(tmpPath)
	}()

	// Write ZIP to temp file
	f.zip64Entries = nil // Reset before writing
	zw := f.ZipWriter(tmpFile)
	f.configureZipCompression(zw)
	if err := f.writeToZip(zw); err != nil {
		_ = zw.Close()
		return 0, err
	}
	if err := zw.Close(); err != nil {
		return 0, err
	}

	// If ZIP64 entries exist, we need to fixup the local file headers
	if len(f.zip64Entries) > 0 {
		if err := f.writeZip64LFHFile(tmpFile); err != nil {
			return 0, err
		}
	}

	// Read the ZIP file back and encrypt it
	if _, err := tmpFile.Seek(0, 0); err != nil {
		return 0, err
	}
	rawZip, err := io.ReadAll(tmpFile)
	if err != nil {
		return 0, err
	}

	// Encrypt and write to output
	encrypted, err := Encrypt(rawZip, f.options)
	if err != nil {
		return 0, err
	}
	n, err := w.Write(encrypted)
	return int64(n), err
}

// countWriter wraps an io.Writer and counts bytes written.
type countWriter struct {
	w io.Writer
	n int64
}

func (cw *countWriter) Write(p []byte) (int, error) {
	n, err := cw.w.Write(p)
	cw.n += int64(n)
	return n, err
}

// WriteToBuffer provides a function to get bytes.Buffer from the saved file,
// and it allocates space in memory. Be careful when the file size is large.
// Consider using WriteTo with a file for large password-protected files to
// reduce memory usage.
func (f *File) WriteToBuffer() (*bytes.Buffer, error) {
	buf := new(bytes.Buffer)
	f.zip64Entries = nil // Reset before writing
	zw := f.ZipWriter(buf)
	f.configureZipCompression(zw)

	if err := f.writeToZip(zw); err != nil {
		_ = zw.Close()
		return buf, err
	}
	if err := zw.Close(); err != nil {
		return buf, err
	}
	// Only perform ZIP64 fixup if we actually have ZIP64 entries
	var err error
	if len(f.zip64Entries) > 0 {
		err = f.writeZip64LFH(buf)
	}
	if f.options != nil && f.options.Password != "" {
		b, err := Encrypt(buf.Bytes(), f.options)
		if err != nil {
			return buf, err
		}
		buf.Reset()
		buf.Write(b)
	}
	return buf, err
}

// writeToZip provides a function to write to ZipWriter.
func (f *File) writeToZip(zw ZipWriter) error {
	f.calcChainWriter()
	f.commentsWriter()
	f.contentTypesWriter()
	f.drawingsWriter()
	f.volatileDepsWriter()
	f.vmlDrawingWriter()
	f.workBookWriter()
	f.workSheetWriter()
	f.relsWriter()
	_ = f.sharedStringsLoader()
	f.sharedStringsWriter()
	f.styleSheetWriter()
	f.themeWriter()

	for path, stream := range f.streams {
		fi, err := zw.Create(path)
		if err != nil {
			return err
		}
		written, err := stream.rawData.CopyTo(fi)
		if err != nil {
			_ = stream.rawData.Close()
			return err
		}
		if written > math.MaxUint32 {
			f.zip64Entries = append(f.zip64Entries, path)
		}
	}
	var (
		n                int
		err              error
		files, tempFiles []string
	)
	f.Pkg.Range(func(path, content interface{}) bool {
		if _, ok := f.streams[path.(string)]; ok {
			return true
		}
		files = append(files, path.(string))
		return true
	})
	sort.Sort(sort.Reverse(sort.StringSlice(files)))
	for _, path := range files {
		var fi io.Writer
		if fi, err = zw.Create(path); err != nil {
			break
		}
		content, _ := f.Pkg.Load(path)
		if n, err = fi.Write(content.([]byte)); int64(n) > math.MaxUint32 {
			f.zip64Entries = append(f.zip64Entries, path)
		}
	}
	f.tempFiles.Range(func(path, content interface{}) bool {
		if _, ok := f.Pkg.Load(path); ok {
			return true
		}
		tempFiles = append(tempFiles, path.(string))
		return true
	})
	sort.Sort(sort.Reverse(sort.StringSlice(tempFiles)))
	for _, path := range tempFiles {
		var fi io.Writer
		if fi, err = zw.Create(path); err != nil {
			break
		}
		if n, err = fi.Write(f.readBytes(path)); int64(n) > math.MaxUint32 {
			f.zip64Entries = append(f.zip64Entries, path)
		}
	}
	return err
}

// writeZip64LFH function sets the ZIP version to 0x2D (45) in the Local File
// Header (LFH). Excel strictly enforces ZIP64 format validation rules. When any
// file within the workbook (OCP) exceeds 4GB in size, the ZIP64 format must be
// used according to the PKZIP specification. However, ZIP files generated using
// Go's standard archive/zip library always set the version in the local file
// header to 20 (ZIP version 2.0) by default, as defined in the internal
// 'writeHeader' function during ZIP creation. The archive/zip package only sets
// the 'ReaderVersion' to 45 (ZIP64 version 4.5) in the central directory for
// entries larger than 4GB. This results in a version mismatch between the
// central directory and the local file header. As a result, opening the
// generated workbook with spreadsheet application will prompt file corruption.
func (f *File) writeZip64LFH(buf *bytes.Buffer) error {
	if len(f.zip64Entries) == 0 {
		return nil
	}
	data, offset := buf.Bytes(), 0
	for offset < len(data) {
		idx := bytes.Index(data[offset:], []byte{0x50, 0x4b, 0x03, 0x04})
		if idx == -1 {
			break
		}
		idx += offset
		if idx+30 > len(data) {
			break
		}
		filenameLen := int(binary.LittleEndian.Uint16(data[idx+26 : idx+28]))
		if idx+30+filenameLen > len(data) {
			break
		}
		if inStrSlice(f.zip64Entries, string(data[idx+30:idx+30+filenameLen]), true) != -1 {
			binary.LittleEndian.PutUint16(data[idx+4:idx+6], 45)
		}
		offset = idx + 1
	}
	return nil
}

// writeZip64LFHFile performs ZIP64 local file header fixup on a file.
// This is used when encrypting to avoid loading the entire file into memory.
func (f *File) writeZip64LFHFile(file *os.File) error {
	if len(f.zip64Entries) == 0 {
		return nil
	}
	// Seek to start of file
	if _, err := file.Seek(0, 0); err != nil {
		return err
	}
	// Read file info to get size
	info, err := file.Stat()
	if err != nil {
		return err
	}
	fileSize := info.Size()

	// Process file in chunks to avoid loading entire file into memory
	const chunkSize = 1024 * 1024 // 1MB chunks
	buf := make([]byte, chunkSize)
	var offset int64

	for offset < fileSize {
		// Read chunk
		n, err := file.ReadAt(buf, offset)
		if err != nil && err != io.EOF {
			return err
		}
		if n == 0 {
			break
		}

		// Search for local file headers in this chunk
		searchBuf := buf[:n]
		searchOffset := 0
		for searchOffset < n {
			idx := bytes.Index(searchBuf[searchOffset:], []byte{0x50, 0x4b, 0x03, 0x04})
			if idx == -1 {
				break
			}
			idx += searchOffset
			absoluteIdx := offset + int64(idx)

			// Check if we have enough data for the header
			if idx+30 > n {
				// Header spans chunk boundary, will be caught in next iteration
				break
			}

			filenameLen := int(binary.LittleEndian.Uint16(searchBuf[idx+26 : idx+28]))
			if idx+30+filenameLen > n {
				// Filename spans chunk boundary, will be caught in next iteration
				break
			}

			filename := string(searchBuf[idx+30 : idx+30+filenameLen])
			if inStrSlice(f.zip64Entries, filename, true) != -1 {
				// Update version field at offset idx+4
				versionBuf := make([]byte, 2)
				binary.LittleEndian.PutUint16(versionBuf, 45)
				if _, err := file.WriteAt(versionBuf, absoluteIdx+4); err != nil {
					return err
				}
			}
			searchOffset = idx + 1
		}

		offset += int64(n)
		// Overlap by 30 bytes to catch headers that span chunks
		if offset < fileSize {
			offset -= 30
		}
	}

	return nil
}
